mapper.select:
SELECT h.household_id AS householdId, h.dong, h.ho, COALESCE(( SELECT hh.status FROM household_history hh WHERE hh.household_id = h.household_id ORDER BY hh.changed_at DESC LIMIT 1 ), '공실') AS status, (SELECT COUNT(*) FROM vehicle v WHERE v.household_id = h.household_id) AS carCount, ( SELECT COUNT(*) FROM user u WHERE u.household_id = h.household_id AND u.status = 'PENDING' AND u.is_deleted = false ) AS pendingCount, GREATEST( h.created_at, COALESCE(( SELECT hh.changed_at FROM household_history hh WHERE hh.household_id = h.household_id ORDER BY hh.changed_at DESC LIMIT 1 ), h.created_at) ) AS lastChangedAt FROM household h
h.dong = #{dong}
AND h.ho LIKE CONCAT('%', #{ho}, '%')
AND COALESCE(( SELECT hh.status FROM household_history hh WHERE hh.household_id = h.household_id ORDER BY hh.changed_at DESC LIMIT 1 ), '공실') = #{status}
ORDER BY pendingCount DESC, h.dong, CAST(h.ho AS UNSIGNED) LIMIT #{startIdx}, #{size}

SELECT COUNT(1) AS totalCount, CEIL(COUNT(1) / #{size}) AS maxPage FROM household h
h.dong = #{dong} AND h.ho LIKE CONCAT('%', #{ho}, '%')
AND COALESCE((SELECT hh.status FROM household_history hh WHERE hh.household_id = h.household_id ORDER BY hh.changed_at DESC LIMIT 1), '공실') = #{status}

SELECT COUNT(*)
FROM household
WHERE dong = #{dong}
  AND ho = #{ho}
